1	import { describe, it, expect } from "vitest";
2	import { processScenario } from "./claim-office.js";
3	
4	describe("MHPCO Claim Office", () => {
5	  describe("Quote - base premiums", () => {
6	    it("returns 5G for an empty item list (processing fee only)", () => {
7	      const result = processScenario({
8	        customer: { yearsWithMHPCO: 0 },
9	        steps: [{ op: "quote" as const, items: [] }],
10	      });
11	      expect(result.results[0]).toEqual({ premium: 5 });
12	    });
13	    it.todo("returns 105G for a single sword (100G base + 5G fee)");
14	    it.todo("returns 65G for a single amulet (60G base + 5G fee)");
15	    it.todo("returns 85G for a single staff (80G base + 5G fee)");
16	    it.todo("returns 45G for a single potion (40G base + 5G fee)");
17	    it.todo("returns 165G for a sword and an amulet (100+60 base + 5G fee)");
18	  });
19	
20	  describe("Quote - component premiums", () => {
21	    it.todo("returns 30G for a single rune (25G base + 5G fee)");
22	    it.todo("returns 55G for 2 runes (50G base + 5G fee)");
23	    it.todo("returns 65G for 3 runes (60G block discount + 5G fee)");
24	    it.todo("returns 105G for 4 runes (no block, 100G base + 5G fee)");
25	    it.todo("returns 180G for 7 runes (175G base + 5G fee)");
26	    it.todo("returns 80G for 2 runes and 1 moonstone (75G, no block, + 5G fee)");
27	    it.todo("returns 125G for 3 runes and 3 moonstones (two blocks, 120G + 5G fee)");
28	  });
29	
30	  describe("Quote - cursed surcharge", () => {
31	    it.todo("adds 50% surcharge to a cursed sword (100+50 base + 5G fee = 155G)");
32	    it.todo("applies curse surcharge only to the cursed item in a multi-item policy");
33	  });
34	
35	  describe("Quote - high enchantment surcharge", () => {
36	    it.todo("adds 30% surcharge for enchantment level 5 (threshold)");
37	    it.todo("does not add surcharge for enchantment level 4");
38	    it.todo("applies both cursed and high enchantment surcharges to same item");
39	  });
40	
41	  describe("Quote - first insurance surcharge", () => {
42	    it.todo("adds 10% first insurance surcharge to policy base premium");
43	    it.todo("applies first insurance surcharge to every quote regardless of customer history");
44	  });
45	
46	  describe("Quote - loyalty discount", () => {
47	    it.todo("applies 20% loyalty discount for customer with 2 years (threshold)");
48	    it.todo("does not apply loyalty discount for customer with 1 year");
49	  });
50	
51	  describe("Quote - follow-up contract discount", () => {
52	    it.todo("applies 15% discount on second quote in scenario");
53	    it.todo("does not apply discount on first quote in scenario");
54	  });
55	
56	  describe("Quote - rounding", () => {
57	    it.todo("rounds premium up in MHPCO favor (ceiling)");
58	  });
59	
60	  describe("Quote - integration", () => {
61	    it.todo("newcomer with cursed sword: 0 years, first contract = 165G");
62	    it.todo("long-standing customer second contract: cursed sword ench 7 = 160G");
63	  });
64	
65	  describe("Quote - errors", () => {
66	    it.todo("rejects unknown item type with non-zero exit");
67	  });
68	
69	  describe("Claim - standard reimbursement", () => {
70	    it.todo("reimburses damage minus 100G deductible for a regular item");
71	    it.todo("reimburses damage to a component minus 100G deductible");
72	  });
73	
74	  describe("Claim - deductible per item", () => {
75	    it.todo("applies deductible separately to each damaged item in same event");
76	  });
77	
78	  describe("Claim - high enchantment reimbursement", () => {
79	    it.todo("reimburses 50% of damage then deductible for enchantment >= 8");
80	  });
81	
82	  describe("Claim - dragon material reimbursement", () => {
83	    it.todo("reimburses full damage then deductible for dragon material item");
84	  });
85	
86	  describe("Claim - dragon material + high enchantment", () => {
87	    it.todo("applies 50% rule when both dragon material and enchantment >= 8");
88	    it.todo("applies full reimbursement for dragon material with enchantment < 8");
89	  });
90	
91	  describe("Claim - cap", () => {
92	    it.todo("caps total payout at 2x insurance sum");
93	    it.todo("tracks remaining cap across multiple claims on same policy");
94	    it.todo("insurance sum uses unmodified item values, not premiums");
95	    it.todo("component block discount does not affect insurance sum");
96	  });
97	
98	  describe("Claim - multiple items of same type", () => {
99	    it.todo("treats each damage entry separately with its own deductible");
100	    it.todo("rejects claim with more damages of a type than policy covers");
101	  });
102	
103	  describe("Claim - errors", () => {
104	    it.todo("rejects damage to item not covered by policy");
105	    it.todo("rejects negative damage amount");
106	  });
107	});
